#!/bin/bash
# Update the current() procedure to add debug logging and _debug response

sed -i '218s/.*/      \/\/ DEBUG: Log what we'\''re passing to the interpreter\n      console.log("[Profection.current] DEBUG: Time Lord:", profection.timeLord);\n      console.log("[Profection.current] DEBUG: Natal Bodies count:", natalBodies.length);\n      const timeLordBody = natalBodies.find(b => b.planet === profection.timeLord);\n      if (timeLordBody) {\n        console.log("[Profection.current] DEBUG: Time Lord Natal:", {\n          planet: timeLordBody.planet,\n          sign: timeLordBody.sign,\n          house: timeLordBody.house,\n          nakshatra: timeLordBody.nakshatra,\n          pada: timeLordBody.pada,\n        });\n      }\n\n      const interpretation = generateProfectionInterpretation(profection, natalChart);\n\n      return {\n        profection,\n        interpretation,\n        _debug: {\n          timeLord: profection.timeLord,\n          natalTimeLord: timeLordBody || null,\n          operationalChain: interpretation.operationalChain,\n          interpretationSource: "generated",\n        }\n      };/' server/profection/router.ts
